using System;
using System.Collections.Generic;
using UnityEngine;
using LitJson;
using kube;

namespace MadnessCubedOffline
{
    public static class MissionsCore
    {
        private static LocalPlayerData Data { get { return CoreManager.PlayerData; } }
        private static string _cachedJson = null;
        private static Dictionary<int, string> _bonusCache = new Dictionary<int, string>();
        private static Dictionary<int, int> _moneyCache = new Dictionary<int, int>();
        private static Dictionary<int, int> _goldCache = new Dictionary<int, int>();

        public static void InvalidateCache()
        {
            _cachedJson = null;
        }

        public static string BuildMissionsJson()
        {
            if (_cachedJson != null) return _cachedJson;
            string raw = GetRawJson();
            raw = raw.Replace(";;", ";");
            CacheMissionData(raw);
            try
            {
                JsonData data = JsonMapper.ToObject(raw);
                JsonData mss = data["mss"];
                for (int i = 0; i < mss.Count; i++)
                {
                    int id = int.Parse(mss[i]["id"].ToString());
                    if (Data.missionScore == null || id >= Data.missionScore.Length || Data.missionScore[id] == 0)
                    {
                        mss[i]["score"] = "0";
                    }
                }
                _cachedJson = JsonMapper.ToJson(data);
            }
            catch (Exception ex)
            {
                Debug.LogError("[Offline] BuildMissionsJson error: " + ex.Message);
                _cachedJson = raw;
            }
            return _cachedJson;
        }

        private static void CacheMissionData(string raw)
        {
            try
            {
                JsonData data = JsonMapper.ToObject(raw);
                JsonData mss = data["mss"];
                for (int i = 0; i < mss.Count; i++)
                {
                    int id = int.Parse(mss[i]["id"].ToString());
                    if (mss[i].Keys.Contains("bonus"))
                        _bonusCache[id] = mss[i]["bonus"].ToString();
                    if (mss[i].Keys.Contains("money"))
                        _moneyCache[id] = int.Parse(mss[i]["money"].ToString());
                    if (mss[i].Keys.Contains("gold"))
                        _goldCache[id] = int.Parse(mss[i]["gold"].ToString());
                }
            }
            catch (Exception ex)
            {
                Debug.LogError("[Offline] CacheMissionData: " + ex.Message);
            }
        }

