        public static string HandleEndMission(int score, int money, int frags)
        {
            ProfileCore.SyncFromGame();
            Data.exp += (uint)score;
            Data.money1 += money;
            Data.frags += frags;
            return "{\"firsttime\":true,\"money\":\"" + money + "\",\"gold\":\"1\",\"exp\":\"" + Data.exp + "\",\"frags\":\"" + Data.frags + "\",\"level\":\"" + Data.level + "\",\"bonus\":\"0\"}";
        }

        public static string HandleMissionEnd(int missionId, int deltaExp, int deltaMoney, int deltaFrags)
        {
            return HandleMissionEndWithLevel(missionId, deltaExp, deltaMoney, deltaFrags, -1);
        }

        public static string HandleMissionEndWithLevel(int missionId, int deltaExp, int deltaMoney, int deltaFrags, int newLevel)
        {
            ProfileCore.SyncFromGame();
            bool firstTime = (missionId >= Data.missionScore.Length || Data.missionScore[missionId] == 0);
            Data.exp += (uint)deltaExp;
            Data.frags += deltaFrags;
            if (missionId < Data.missionScore.Length)
                Data.missionScore[missionId] = 1;
            string bonusStr = _bonusCache.ContainsKey(missionId) ? _bonusCache[missionId] : "0";
            int rewardMoney = _moneyCache.ContainsKey(missionId) ? _moneyCache[missionId] : deltaMoney;
            int rewardGold = _goldCache.ContainsKey(missionId) ? _goldCache[missionId] : 0;
            Data.money1 += rewardMoney;
            Data.money2 += rewardGold;
            if (newLevel > Data.level)
            {
                int levelUpReward = (newLevel - Data.level) * 1000;
                Data.money1 += levelUpReward;
                Data.level = newLevel;
            }
            ProcessBonusItems(bonusStr);
            string bonusField = string.IsNullOrEmpty(bonusStr) || bonusStr == "0" ? "0" : bonusStr;
            string json = "{\"firsttime\":" + (firstTime ? "true" : "false") +
                          ",\"money\":\"" + rewardMoney + "\"" +
                          ",\"gold\":\"" + rewardGold + "\"" +
                          ",\"exp\":\"" + Data.exp + "\"" +
                          ",\"frags\":\"" + Data.frags + "\"" +
                          ",\"level\":\"" + Data.level + "\"" +
                          ",\"bonus\":\"" + bonusField + "\"}";
            if (CoreEvents.OnMissionCompleted != null)
                CoreEvents.OnMissionCompleted("mission_" + missionId);
            InvalidateCache();
            return json;
        }

        private static void ProcessBonusItems(string bonusStr)
        {
            if (string.IsNullOrEmpty(bonusStr) || bonusStr == "0") return;
            string[] parts = bonusStr.Split(';');
            for (int i = 0; i + 1 < parts.Length; i += 2)
            {
                string typeStr = parts[i];
                if (string.IsNullOrEmpty(typeStr)) continue;
                int count;
                if (!int.TryParse(parts[i + 1], out count) || count <= 0) continue;
                char first = typeStr[0];
                if (first == 'w' || first == 'W')
                {
                    int weaponId;
                    if (int.TryParse(typeStr.Substring(1), out weaponId) && weaponId >= 0 && weaponId < Data.weapons.Length)
                    {
                        Data.weapons[weaponId] = 1;
                        if (weaponId < Data.weaponUnlock.Length)
                            Data.weaponUnlock[weaponId] = 1;
                    }
                }
                else if (first >= '0' && first <= '9')
                {
                    int itemId;
                    if (int.TryParse(typeStr, out itemId) && itemId >= 0 && itemId < Data.items.Length)
                        Data.items[itemId] += count;
                }
            }
        }

        public static void ProcessBonusItemsOnGPS(string bonusStr)
        {
            if (string.IsNullOrEmpty(bonusStr) || bonusStr == "0") return;
            if (Kube.GPS == null) return;
            string[] parts = bonusStr.Split(';');
            for (int i = 0; i + 1 < parts.Length; i += 2)
            {
                string typeStr = parts[i];
                if (string.IsNullOrEmpty(typeStr)) continue;
                int count;
                if (!int.TryParse(parts[i + 1], out count) || count <= 0) continue;
                char first = typeStr[0];
                if (first == 'w' || first == 'W')
                {
                    int weaponId;
                    if (int.TryParse(typeStr.Substring(1), out weaponId) && weaponId >= 0 && Kube.GPS.inventarWeapons != null && weaponId < Kube.GPS.inventarWeapons.Length)
                    {
                        Kube.GPS.inventarWeapons[weaponId] = (int)UnityEngine.Time.time + count * 86400;
                        if (Kube.IS != null)
                            Kube.IS.putToFastInvetar(1, new FastInventar(4, weaponId));
                    }
                }
                else if (first >= '0' && first <= '9')
                {
                    int itemId;
                    if (int.TryParse(typeStr, out itemId) && itemId >= 0 && Kube.GPS.inventarItems != null && itemId < Kube.GPS.inventarItems.Length)
                        Kube.GPS.inventarItems[itemId] += count;
                }
            }
        }

